import { createClient } from './server';
import { AdminPermission } from '@/types';

export async function getAdminPermissions(userId: string): Promise<AdminPermission | null> {
  const supabase = await createClient();
  
  const { data, error } = await supabase
    .from('admin_permissions')
    .select('*')
    .eq('user_id', userId)
    .single();

  if (error || !data) {
    return null;
  }

  return data as AdminPermission;
}

export async function checkPermission(userId: string, permission: keyof AdminPermission): Promise<boolean> {
  const permissions = await getAdminPermissions(userId);
  if (!permissions) return false;
  
  const val = permissions[permission];
  return typeof val === 'boolean' ? val : false;
}
