import { createClient } from '@/lib/supabase/server';
import { getAdminPermissions } from '@/lib/supabase/permissions';
import { AdminPermission } from '@/types';
import { Users, Shield, Crown } from 'lucide-react';
import { Button } from '@/components/ui/Button';

export const metadata = {
  title: 'Manage Members | Admin Portal',
};

export default async function AdminMembersPage() {
  const supabase = await createClient();

  const { data: { user } } = await supabase.auth.getUser();
  if (!user) {
    return <div>Unauthorized</div>;
  }

  const permissions = await getAdminPermissions(user.id);
  if (!permissions || permissions.role !== 'super_admin') {
    return <div>Access Denied</div>;
  }

  // Fetch all admin permissions
  const { data: allPermissions, error } = await supabase
    .from('admin_permissions')
    .select('*, auth.users(email)')
    .order('created_at', { ascending: false });

  if (error) {
    console.error('Error fetching permissions:', error);
  }

  return (
    <div className="space-y-10 animate-in fade-in slide-in-from-bottom-4 duration-1000">
      <div className="flex flex-col md:flex-row md:items-center justify-between gap-8">
        <div>
          <div className="flex items-center gap-3 mb-2">
            <div className="w-2 h-8 bg-saffron rounded-full shadow-[0_0_15px_rgba(245,158,11,0.5)]" />
            <h1 className="text-5xl font-bold font-heading text-white tracking-tight">
              Member <span className="text-white/40">Management</span>
            </h1>
          </div>
          <p className="text-white/50 font-medium italic pl-5">Grant and revoke access to the sacred archives.</p>
        </div>
      </div>

      <div className="glass-card overflow-hidden border border-white/5 shadow-2xl rounded-[2.5rem] bg-white/[0.02] backdrop-blur-3xl">
        <div className="overflow-x-auto">
          <table className="w-full text-left border-collapse">
            <thead>
              <tr className="bg-white/[0.03] border-b border-white/10 text-white/30 text-[10px] font-black uppercase tracking-[0.3em]">
                <th className="px-10 py-7">Member</th>
                <th className="px-10 py-7 text-center">Role</th>
                <th className="px-10 py-7 text-center">View</th>
                <th className="px-10 py-7 text-center">Write</th>
                <th className="px-10 py-7 text-center">Edit</th>
                <th className="px-10 py-7 text-center">Delete</th>
                <th className="px-10 py-7 text-right">Actions</th>
              </tr>
            </thead>
            <tbody className="divide-y divide-white/5">
              {allPermissions && allPermissions.length > 0 ? (
                allPermissions.map((perm: any) => (
                  <tr key={perm.user_id} className="hover:bg-white/[0.04] transition-all duration-500 group">
                    <td className="px-10 py-8">
                      <div className="font-bold text-white group-hover:text-saffron transition-colors text-lg">
                        {perm.users?.email || perm.user_id}
                      </div>
                    </td>
                    <td className="px-10 py-8 text-center">
                      <span className={`inline-flex items-center gap-2 px-3 py-1 rounded-full text-xs font-bold ${
                        perm.role === 'super_admin' ? 'bg-purple-500/20 text-purple-300 border border-purple-500/30' :
                        perm.role === 'editor' ? 'bg-blue-500/20 text-blue-300 border border-blue-500/30' :
                        'bg-gray-500/20 text-gray-300 border border-gray-500/30'
                      }`}>
                        {perm.role === 'super_admin' && <Crown size={12} />}
                        {perm.role}
                      </span>
                    </td>
                    <td className="px-10 py-8 text-center">
                      <span className={`w-3 h-3 rounded-full ${perm.can_view ? 'bg-green-400' : 'bg-red-400'}`} />
                    </td>
                    <td className="px-10 py-8 text-center">
                      <span className={`w-3 h-3 rounded-full ${perm.can_write ? 'bg-green-400' : 'bg-red-400'}`} />
                    </td>
                    <td className="px-10 py-8 text-center">
                      <span className={`w-3 h-3 rounded-full ${perm.can_edit ? 'bg-green-400' : 'bg-red-400'}`} />
                    </td>
                    <td className="px-10 py-8 text-center">
                      <span className={`w-3 h-3 rounded-full ${perm.can_delete ? 'bg-green-400' : 'bg-red-400'}`} />
                    </td>
                    <td className="px-10 py-8 text-right">
                      <Button variant="ghost" size="sm" className="text-saffron hover:text-white hover:bg-saffron/10">
                        Edit Permissions
                      </Button>
                    </td>
                  </tr>
                ))
              ) : (
                <tr>
                  <td colSpan={7} className="px-10 py-20 text-center text-white/40">
                    No members found
                  </td>
                </tr>
              )}
            </tbody>
          </table>
        </div>
      </div>
    </div>
  );
}